/// Which MOD effect type "owns" a given byte of the block.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ModTypeOwner {
    Distortion,
    Wah,
    Compressor,
    Limiter,
    Octave,
    Phaser,
    Flanger,
    Tremolo,
    Rotary,
    UniVibe,
    Panner,
    Delay,
    Chorus,
    Equalizer,
}

/// One byte of the MOD parameter block.
#[derive(Debug, Clone, Copy)]
pub struct ParamEntry {
    pub page: u8,
    pub offset: u8,
    pub owning_type: Option<ModTypeOwner>,
    pub name: &'static str,
    /// Named byte values (empty for purely-numeric params).
    pub values: &'static [(u8, &'static str)],
    /// Raw wire-byte range (min, max). None when purely enumerated.
    pub range: Option<(u8, u8)>,
    /// Display range (min, max) when it differs from the wire range.
    pub display_range: Option<(i32, i32)>,
    /// Tooltip-friendly description from the owner's manual.
    pub help: &'static str,
}

pub const MOD_BLOCK_SIZE: usize = 128;

